const moduleLoaders = {
  calculators: () => import("../tools/CalculatorTools"),
  conversion: () => import("../tools/ConversionTools"),
  "dev-tech": () => import("../tools/DevTools"),
  "text-data": () => import("../tools/TextDataTools"),
  "file-tools": () => import("../tools/FileTools"),
  generators: () => import("../tools/GeneratorTools"),
  productivity: () => import("../tools/ProductivityTools"),
  longtail: () => import("../tools/LongTailTools")
};

function addRequestedTool(category, slug, name, shortDescription, tags, inputModel, outputModel, moduleKey, exportName) {
  return tool(category, {
    slug,
    name,
    shortDescription,
    seoTitle: name,
    seoDescription: `${shortDescription} Locally in the browser with no upload.`,
    tags,
    inputModel,
    outputModel,
    component: lazyTool(moduleLoaders[moduleKey], exportName)
  });
}

